struct BorrowedPlainPubsubNumsubPacket<'a> {
    consumed: usize,
    sub: &'a [u8],
    channels: Vec<&'a [u8]>,
}

// (BlackThrush) Variadic byte-prefix fast path for `PUBSUB NUMSUB|SHARDNUMSUB ch...`
// (the *3+ form). Mirrors the GEOHASH variadic header parse: *N, then $6 PUBSUB, then
// the subcommand token (any length), then the count-2 channel args. The execute claims
// NUMSUB + SHARDNUMSUB and defers other subcommands.
fn parse_borrowed_plain_pubsub_numsub_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainPubsubNumsubPacket<'a>> {
    if config.max_bulk_len < b"PUBSUB".len() || *input.first()? != b'*' {
        return None;
    }
    let mut idx = 1;
    let mut count = 0usize;
    let mut digits = 0usize;
    while let Some(&b) = input.get(idx) {
        if b == b'\r' {
            break;
        }
        if !b.is_ascii_digit() {
            return None;
        }
        count = count.checked_mul(10)?.checked_add(usize::from(b - b'0'))?;
        idx += 1;
        digits += 1;
    }
    if digits == 0 || count < 3 || config.max_array_len < count {
        return None;
    }
    if input.get(idx..idx + 2)? != b"\r\n" {
        return None;
    }
    idx += 2;
    if input.get(idx..idx + 4)? != b"$6\r\n" {
        return None;
    }
    idx += 4;
    if !input.get(idx..idx + 6)?.eq_ignore_ascii_case(b"PUBSUB") {
        return None;
    }
    idx += 6;
    if input.get(idx..idx + 2)? != b"\r\n" {
        return None;
    }
    idx += 2;
    // Subcommand token of any length (NUMSUB=6 / SHARDNUMSUB=11). The execute
    // claims NUMSUB + SHARDNUMSUB and defers any other variadic subcommand.
    let (sub, mut cursor) = parse_borrowed_plain_set_bulk(input, idx, config.max_bulk_len)?;
    let channel_count = count - 2;
    let mut channels = Vec::with_capacity(channel_count);
    for _ in 0..channel_count {
        let (channel, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
        channels.push(channel);
        cursor = next;
    }
    Some(BorrowedPlainPubsubNumsubPacket {
        consumed: cursor,
        sub,
        channels,
    })
}

// (BlackThrush) Byte-prefix fast path for the *2 form `PUBSUB <subcommand>` (i.e.
// NUMPAT — CHANNELS/SHARDCHANNELS also fit *2 but the execute only claims NUMPAT and
// defers the rest). Mirrors the STRLEN single-arg packet.
fn parse_borrowed_plain_pubsub_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainPubsubPacket<'a>> {
    if config.max_array_len < 2 || config.max_bulk_len < b"PUBSUB".len() {
        return None;
    }
    let mut cursor = input.strip_prefix(b"*2\r\n$6\r\n").and_then(|rest| {
        rest.get(..6)
            .filter(|command| command.eq_ignore_ascii_case(b"PUBSUB"))
            .map(|_| input.len() - rest.len() + 6)
    })?;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (sub, consumed) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    Some(BorrowedPlainPubsubPacket { consumed, sub })
}

