// (CrimsonHawk) Byte-prefix fast path for single-key XREADGROUP HISTORY read:
//   *7  XREADGROUP GROUP g c STREAMS key id
//   *9  XREADGROUP GROUP g c COUNT n STREAMS key id
// The COUNT/no-COUNT expectation is tied to the exact array count so a multi-key `*9`
// (XREADGROUP GROUP g c STREAMS k1 k2 i1 i2) is REJECTED (its token after `c` is STREAMS, not COUNT),
// not mis-framed. NOACK / BLOCK / multi-key / `>` all defer to generic dispatch.
fn parse_borrowed_plain_xreadgroup_history_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainXreadgroupHistoryPacket<'a>> {
    if config.max_bulk_len < b"XREADGROUP".len() {
        return None;
    }
    let after_cmd = |prefix: &[u8]| -> Option<usize> {
        let mut cursor = input.strip_prefix(prefix).and_then(|rest| {
            rest.get(..10)
                .filter(|c| c.eq_ignore_ascii_case(b"XREADGROUP"))
                .map(|_| input.len() - rest.len() + 10)
        })?;
        if input.get(cursor..cursor + 2)? != b"\r\n" {
            return None;
        }
        cursor += 2;
        Some(cursor)
    };
    let bulk = |cur: usize| parse_borrowed_plain_set_bulk(input, cur, config.max_bulk_len);
    // *7 — no COUNT.
    if let Some(cursor) = after_cmd(b"*7\r\n$10\r\n") {
        let (kw_group, next) = bulk(cursor)?;
        if !kw_group.eq_ignore_ascii_case(b"GROUP") {
            return None;
        }
        let (group, next) = bulk(next)?;
        let (consumer, next) = bulk(next)?;
        let (streams, next) = bulk(next)?;
        if !streams.eq_ignore_ascii_case(b"STREAMS") {
            return None;
        }
        let (key, next) = bulk(next)?;
        let (id, consumed) = bulk(next)?;
        return Some(BorrowedPlainXreadgroupHistoryPacket {
            consumed,
            group,
            consumer,
            key,
            id,
            count: None,
        });
    }
    // *9 — COUNT n (single key only; multi-key *9 has STREAMS here and is rejected).
    if let Some(cursor) = after_cmd(b"*9\r\n$10\r\n") {
        let (kw_group, next) = bulk(cursor)?;
        if !kw_group.eq_ignore_ascii_case(b"GROUP") {
            return None;
        }
        let (group, next) = bulk(next)?;
        let (consumer, next) = bulk(next)?;
        let (kw_count, next) = bulk(next)?;
        if !kw_count.eq_ignore_ascii_case(b"COUNT") {
            return None;
        }
        let (count, next) = bulk(next)?;
        let (streams, next) = bulk(next)?;
        if !streams.eq_ignore_ascii_case(b"STREAMS") {
            return None;
        }
        let (key, next) = bulk(next)?;
        let (id, consumed) = bulk(next)?;
        return Some(BorrowedPlainXreadgroupHistoryPacket {
            consumed,
            group,
            consumer,
            key,
            id,
            count: Some(count),
        });
    }
    None
}

const XREAD_MULTI_MAX: usize = 8;

struct BorrowedPlainXreadMultiPacket<'a> {
    consumed: usize,
    /// The `k` stream keys followed by the `k` ids (parallel), `k = stream_count`.
    keys: [&'a [u8]; XREAD_MULTI_MAX],
    ids: [&'a [u8]; XREAD_MULTI_MAX],
    stream_count: usize,
    count: Option<&'a [u8]>,
}

// (CrimsonHawk) Byte-prefix fast path for MULTI-key (2..=8 streams) non-blocking XREAD:
//   XREAD [COUNT n] STREAMS k1..km i1..im   (array len = 2m+2 or 2m+4)
// Single key (m==1) is handled by the dedicated single packet; BLOCK / >8 streams / odd tails defer
// to generic borrowed dispatch. Distinguishes the COUNT form by requiring COUNT at token 1.
fn parse_borrowed_plain_xread_multi_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainXreadMultiPacket<'a>> {
    if config.max_bulk_len < b"STREAMS".len() {
        return None;
    }
    let rest = input.strip_prefix(b"*")?;
    if rest.first() == Some(&b'0') {
        return None;
    }
    let mut i = 0usize;
    let mut arr_len = 0usize;
    while let Some(&b) = rest.get(i) {
        if !b.is_ascii_digit() {
            break;
        }
        arr_len = arr_len.checked_mul(10)?.checked_add((b - b'0') as usize)?;
        i += 1;
        if i > 3 {
            return None;
        }
    }
    if i == 0 || rest.get(i..i + 2)? != b"\r\n" {
        return None;
    }
    let mut cursor = 1 + i + 2; // past '*', digits, CRLF
    // Command token.
    let (cmd, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    if !cmd.eq_ignore_ascii_case(b"XREAD") {
        return None;
    }
    cursor = next;
    // Optional COUNT n (token 1). BLOCK is NOT accepted here → generic.
    let mut count: Option<&[u8]> = None;
    let mut body_tokens = arr_len.checked_sub(1)?; // minus the command
    let (first, after_first) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    if first.eq_ignore_ascii_case(b"COUNT") {
        let (n, after_n) = parse_borrowed_plain_set_bulk(input, after_first, config.max_bulk_len)?;
        count = Some(n);
        cursor = after_n;
        body_tokens -= 2;
        let (kw, after_kw) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
        if !kw.eq_ignore_ascii_case(b"STREAMS") {
            return None;
        }
        cursor = after_kw;
        body_tokens -= 1;
    } else {
        if !first.eq_ignore_ascii_case(b"STREAMS") {
            return None;
        }
        cursor = after_first;
        body_tokens -= 1;
    }
    // body_tokens must be an even 2m with 2 <= m <= MAX (m==1 handled by the single parser).
    if body_tokens < 4 || !body_tokens.is_multiple_of(2) {
        return None;
    }
    let m = body_tokens / 2;
    if m > XREAD_MULTI_MAX {
        return None;
    }
    let mut slots: [&[u8]; XREAD_MULTI_MAX * 2] = [b""; XREAD_MULTI_MAX * 2];
    let mut consumed = cursor;
    for slot in slots.iter_mut().take(body_tokens) {
        let (bulk, next) = parse_borrowed_plain_set_bulk(input, consumed, config.max_bulk_len)?;
        *slot = bulk;
        consumed = next;
    }
    let mut keys: [&[u8]; XREAD_MULTI_MAX] = [b""; XREAD_MULTI_MAX];
    let mut ids: [&[u8]; XREAD_MULTI_MAX] = [b""; XREAD_MULTI_MAX];
    keys[..m].copy_from_slice(&slots[..m]);
    ids[..m].copy_from_slice(&slots[m..2 * m]);
    Some(BorrowedPlainXreadMultiPacket {
        consumed,
        keys,
        ids,
        stream_count: m,
        count,
    })
}

struct BorrowedPlainXreadSinglePacket<'a> {
    consumed: usize,
    key: &'a [u8],
    id: &'a [u8],
    count: Option<&'a [u8]>,
}

// (CrimsonHawk) Byte-prefix fast path for single-key non-blocking XREAD:
//   *4  XREAD STREAMS key id
//   *6  XREAD COUNT n STREAMS key id
// Multi-key, BLOCK, and every other shape defer to generic borrowed dispatch. The `*6` COUNT form is
// distinguished from the multi-key `*6` (XREAD STREAMS k1 k2 i1 i2) by requiring COUNT at token 1.
fn parse_borrowed_plain_xread_single_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainXreadSinglePacket<'a>> {
    if config.max_bulk_len < b"STREAMS".len() {
        return None;
    }
    let after_cmd = |prefix: &[u8]| -> Option<usize> {
        let mut cursor = input.strip_prefix(prefix).and_then(|rest| {
            rest.get(..5)
                .filter(|c| c.eq_ignore_ascii_case(b"XREAD"))
                .map(|_| input.len() - rest.len() + 5)
        })?;
        if input.get(cursor..cursor + 2)? != b"\r\n" {
            return None;
        }
        cursor += 2;
        Some(cursor)
    };
    // No-count: *4 XREAD STREAMS key id
    if let Some(cursor) = after_cmd(b"*4\r\n$5\r\n") {
        let (streams, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
        if !streams.eq_ignore_ascii_case(b"STREAMS") {
            return None;
        }
        let (key, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
        let (id, consumed) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
        return Some(BorrowedPlainXreadSinglePacket {
            consumed,
            key,
            id,
            count: None,
        });
    }
    // Count: *6 XREAD COUNT n STREAMS key id
    if let Some(cursor) = after_cmd(b"*6\r\n$5\r\n") {
        let (kw, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
        if !kw.eq_ignore_ascii_case(b"COUNT") {
            return None;
        }
        let (count, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
        let (streams, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
        if !streams.eq_ignore_ascii_case(b"STREAMS") {
            return None;
        }
        let (key, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
        let (id, consumed) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
        return Some(BorrowedPlainXreadSinglePacket {
            consumed,
            key,
            id,
            count: Some(count),
        });
    }
    None
}

