/// `ZLEXCOUNT key min max` fast-path packet (4-element multibulk, 9-byte command
/// token). The runtime fast path validates the lex bounds and falls back to the
/// generic handler on a malformed bound (for the exact error). (cc ZLEXCOUNT)
fn parse_borrowed_plain_zlexcount_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainZlexcountPacket<'a>> {
    if config.max_array_len < 4 || config.max_bulk_len < b"ZLEXCOUNT".len() {
        return None;
    }
    if !input.starts_with(b"*4\r\n$9\r\n") {
        return None;
    }
    let mut cursor = "*4\r\n$9\r\n".len();
    if input
        .get(cursor..cursor + 9)?
        .eq_ignore_ascii_case(b"ZLEXCOUNT")
    {
        cursor += 9;
    } else {
        return None;
    }
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (key, next1) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let (min, next2) = parse_borrowed_plain_set_bulk(input, next1, config.max_bulk_len)?;
    let (max, consumed) = parse_borrowed_plain_set_bulk(input, next2, config.max_bulk_len)?;
    Some(BorrowedPlainZlexcountPacket {
        consumed,
        key,
        min,
        max,
    })
}

struct BorrowedPlainGeodistPacket<'a> {
    consumed: usize,
    key: &'a [u8],
    m1: &'a [u8],
    m2: &'a [u8],
    to_meter: f64,
    unit: Option<&'a [u8]>,
}

/// `GEODIST key m1 m2 [unit]` fast-path packet (4- or 5-element multibulk, 7-byte
/// command token). For the 5-element form the unit is validated here via
/// `geo_unit_to_meters`; an unknown unit (or any other shape) returns None so the
/// generic `geodist` handler emits the exact error. The runtime fast path then
/// serves a pure read. (frankenredis cc GEODIST fast path)
fn parse_borrowed_plain_geodist_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainGeodistPacket<'a>> {
    if config.max_array_len < 4 || config.max_bulk_len < b"GEODIST".len() {
        return None;
    }
    let has_unit = if input.starts_with(b"*5\r\n$7\r\n") {
        true
    } else if input.starts_with(b"*4\r\n$7\r\n") {
        false
    } else {
        return None;
    };
    let mut cursor = "*4\r\n$7\r\n".len();
    if input
        .get(cursor..cursor + 7)?
        .eq_ignore_ascii_case(b"GEODIST")
    {
        cursor += 7;
    } else {
        return None;
    }
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (key, next1) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let (m1, next2) = parse_borrowed_plain_set_bulk(input, next1, config.max_bulk_len)?;
    let (m2, next3) = parse_borrowed_plain_set_bulk(input, next2, config.max_bulk_len)?;
    let (to_meter, unit, consumed) = if has_unit {
        let (unit, next4) = parse_borrowed_plain_set_bulk(input, next3, config.max_bulk_len)?;
        let meters = fr_command::geo_unit_to_meters(unit)?;
        (meters, Some(unit), next4)
    } else {
        (1.0, None, next3)
    };
    Some(BorrowedPlainGeodistPacket {
        consumed,
        key,
        m1,
        m2,
        to_meter,
        unit,
    })
}

struct BorrowedPlainGeoposPacket<'a> {
    consumed: usize,
    key: &'a [u8],
    members: Vec<&'a [u8]>,
}

/// `GEOPOS key member [member ...]` fast-path packet (variable-arity multibulk,
/// 6-byte command token, >=1 member). Returns None for any other shape so the
/// generic `geopos` handler stays authoritative (arity error, etc.). The runtime
/// fast path then serves a pure read. (frankenredis cc GEOPOS fast path)
fn parse_borrowed_plain_geopos_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainGeoposPacket<'a>> {
    if config.max_bulk_len < b"GEOPOS".len() || *input.first()? != b'*' {
        return None;
    }
    // Parse the multibulk element count: GEOPOS + key + N members (>= 3 total).
    let mut idx = 1;
    let mut count = 0usize;
    let mut digits = 0usize;
    while let Some(&b) = input.get(idx) {
        if b == b'\r' {
            break;
        }
        if !b.is_ascii_digit() {
            return None;
        }
        count = count.checked_mul(10)?.checked_add(usize::from(b - b'0'))?;
        idx += 1;
        digits += 1;
    }
    if digits == 0 || count < 3 || config.max_array_len < count {
        return None;
    }
    if input.get(idx..idx + 2)? != b"\r\n" {
        return None;
    }
    idx += 2;
    // Command token: $6\r\nGEOPOS\r\n
    if input.get(idx..idx + 4)? != b"$6\r\n" {
        return None;
    }
    idx += 4;
    if !input.get(idx..idx + 6)?.eq_ignore_ascii_case(b"GEOPOS") {
        return None;
    }
    idx += 6;
    if input.get(idx..idx + 2)? != b"\r\n" {
        return None;
    }
    idx += 2;
    let (key, mut cursor) = parse_borrowed_plain_set_bulk(input, idx, config.max_bulk_len)?;
    let member_count = count - 2;
    let mut members = Vec::with_capacity(member_count);
    for _ in 0..member_count {
        let (member, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
        members.push(member);
        cursor = next;
    }
    Some(BorrowedPlainGeoposPacket {
        consumed: cursor,
        key,
        members,
    })
}

struct BorrowedPlainGeohashPacket<'a> {
    consumed: usize,
    key: &'a [u8],
    members: Vec<&'a [u8]>,
}

/// `GEOHASH key member member [member ...]` fast-path packet (variable-arity
/// multibulk, mirror of the GEOPOS packet parser with the $7\r\nGEOHASH command
/// token). The single-member shape stays on the exact key+arg parser.
fn parse_borrowed_plain_geohash_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainGeohashPacket<'a>> {
    if config.max_bulk_len < b"GEOHASH".len() || *input.first()? != b'*' {
        return None;
    }
    let mut idx = 1;
    let mut count = 0usize;
    let mut digits = 0usize;
    while let Some(&b) = input.get(idx) {
        if b == b'\r' {
            break;
        }
        if !b.is_ascii_digit() {
            return None;
        }
        count = count.checked_mul(10)?.checked_add(usize::from(b - b'0'))?;
        idx += 1;
        digits += 1;
    }
    if digits == 0 || count < 4 || config.max_array_len < count {
        return None;
    }
    if input.get(idx..idx + 2)? != b"\r\n" {
        return None;
    }
    idx += 2;
    if input.get(idx..idx + 4)? != b"$7\r\n" {
        return None;
    }
    idx += 4;
    if !input.get(idx..idx + 7)?.eq_ignore_ascii_case(b"GEOHASH") {
        return None;
    }
    idx += 7;
    if input.get(idx..idx + 2)? != b"\r\n" {
        return None;
    }
    idx += 2;
    let (key, mut cursor) = parse_borrowed_plain_set_bulk(input, idx, config.max_bulk_len)?;
    let member_count = count - 2;
    let mut members = Vec::with_capacity(member_count);
    for _ in 0..member_count {
        let (member, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
        members.push(member);
        cursor = next;
    }
    Some(BorrowedPlainGeohashPacket {
        consumed: cursor,
        key,
        members,
    })
}

struct BorrowedPlainBitfieldGetPacket<'a> {
    consumed: usize,
    cmd: PlainBitfieldGetCmd,
    key: &'a [u8],
    get_arg: &'a [u8],
    enc_arg: &'a [u8],
    offset_arg: &'a [u8],
}

/// `BITFIELD[_RO] key GET <enc> <offset>` read-only single-op fast-path packet
/// — extracts the five bulk args of the common bitmap read form. The runtime
/// fast path validates the GET op + encoding/offset and serves it; any other
/// BITFIELD form (SET/INCRBY/OVERFLOW/multi-op/invalid) returns None there and
/// falls to the generic handler.
fn parse_borrowed_plain_bitfield_get_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainBitfieldGetPacket<'a>> {
    if config.max_array_len < 5 || config.max_bulk_len < b"BITFIELD".len() {
        return None;
    }
    let (cmd, mut cursor) = input
        .strip_prefix(b"*5\r\n$8\r\n")
        .and_then(|rest| {
            rest.get(..8)
                .filter(|command| command.eq_ignore_ascii_case(b"BITFIELD"))
                .map(|_| (PlainBitfieldGetCmd::Bitfield, input.len() - rest.len() + 8))
        })
        .or_else(|| {
            if config.max_bulk_len < b"BITFIELD_RO".len() {
                return None;
            }
            input.strip_prefix(b"*5\r\n$11\r\n").and_then(|rest| {
                rest.get(..11)
                    .filter(|command| command.eq_ignore_ascii_case(b"BITFIELD_RO"))
                    .map(|_| {
                        (
                            PlainBitfieldGetCmd::BitfieldRo,
                            input.len() - rest.len() + 11,
                        )
                    })
            })
        })?;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (key, next1) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let (get_arg, next2) = parse_borrowed_plain_set_bulk(input, next1, config.max_bulk_len)?;
    let (enc_arg, next3) = parse_borrowed_plain_set_bulk(input, next2, config.max_bulk_len)?;
    let (offset_arg, consumed) = parse_borrowed_plain_set_bulk(input, next3, config.max_bulk_len)?;
    Some(BorrowedPlainBitfieldGetPacket {
        consumed,
        cmd,
        key,
        get_arg,
        enc_arg,
        offset_arg,
    })
}

struct BorrowedPlainBitfieldSetPacket<'a> {
    consumed: usize,
    key: &'a [u8],
    set_arg: &'a [u8],
    enc_arg: &'a [u8],
    offset_arg: &'a [u8],
    value_arg: &'a [u8],
}

/// `BITFIELD key SET <enc> <offset> <value>` single-op fast-path packet. Runtime
/// keeps the semantic gate narrow and falls back for signed/overflow/multi-op
/// cases so generic BITFIELD remains authoritative for edge behavior.
fn parse_borrowed_plain_bitfield_set_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainBitfieldSetPacket<'a>> {
    if config.max_array_len < 6 || config.max_bulk_len < b"BITFIELD".len() {
        return None;
    }
    let rest = input.strip_prefix(b"*6\r\n$8\r\n")?;
    let command = rest.get(..8)?;
    if !command.eq_ignore_ascii_case(b"BITFIELD") {
        return None;
    }
    let mut cursor = input.len() - rest.len() + 8;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (key, next1) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let (set_arg, next2) = parse_borrowed_plain_set_bulk(input, next1, config.max_bulk_len)?;
    let (enc_arg, next3) = parse_borrowed_plain_set_bulk(input, next2, config.max_bulk_len)?;
    let (offset_arg, next4) = parse_borrowed_plain_set_bulk(input, next3, config.max_bulk_len)?;
    let (value_arg, consumed) = parse_borrowed_plain_set_bulk(input, next4, config.max_bulk_len)?;
    Some(BorrowedPlainBitfieldSetPacket {
        consumed,
        key,
        set_arg,
        enc_arg,
        offset_arg,
        value_arg,
    })
}

