// (frankenredis-ljffq) EXPIRE key seconds (3-element, no option); seconds bulk
// passes as bytes — execute_plain_expire_borrowed parses/validates it. The
// NX/XX/GT/LT option forms (arity 4) fall through to the generic path.
fn parse_borrowed_plain_expire_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainKeyMemberPacket<'a>> {
    if config.max_array_len < 3 || config.max_bulk_len < b"EXPIRE".len() {
        return None;
    }
    let mut cursor = input.strip_prefix(b"*3\r\n$6\r\n").and_then(|rest| {
        rest.get(..6)
            .filter(|command| command.eq_ignore_ascii_case(b"EXPIRE"))
            .map(|_| input.len() - rest.len() + 6)
    })?;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (key, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let (member, consumed) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    Some(BorrowedPlainKeyMemberPacket {
        consumed,
        key,
        member,
    })
}

