// (frankenredis-zmscoremulti) ZMSCORE key m1..mN for 4-8 members (*6..*10) — common
// batch score lookups. Reuses the variadic execute_plain_zmscore_borrowed_into (the
// store skiplist read is cheap, so this is dispatch-bound like the LMPOP/ZMPOP 2-key
// paths); zmscore2/zmscore3 already cover 2-3, only 4+ fell to the generic argv path.
// 9+ members fall through to the generic. Mirrors parse_borrowed_plain_hmget_multi_packet;
// `fields[..len]` holds the borrowed member bulks.
fn parse_borrowed_plain_zmscore_multi_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainHmgetMultiPacket<'a>> {
    if config.max_bulk_len < b"ZMSCORE".len() {
        return None;
    }
    // (CrimsonHawk) Generic array-count parse (with leading-zero guard) serving
    // 4..=32 members on the fast path — same >8 dispatch-cliff fix as HMGET /
    // SMISMEMBER. 1-3 members keep their dedicated paths; >32 defers to generic.
    let rest = input.strip_prefix(b"*")?;
    if rest.first() == Some(&b'0') {
        return None;
    }
    let mut i = 0usize;
    let mut arr_len = 0usize;
    while let Some(&b) = rest.get(i) {
        if !b.is_ascii_digit() {
            break;
        }
        arr_len = arr_len.checked_mul(10)?.checked_add((b - b'0') as usize)?;
        i += 1;
        if i > 3 {
            return None;
        }
    }
    if i == 0 || rest.get(i..i + 2)? != b"\r\n" {
        return None;
    }
    if arr_len < 6 {
        return None;
    }
    let nmembers = arr_len - 2;
    if nmembers > HMGET_MULTI_MAX || config.max_array_len < arr_len {
        return None;
    }
    let mut cursor = 1 + i + 2;
    if input.get(cursor..cursor + 4)? != b"$7\r\n" {
        return None;
    }
    cursor += 4;
    if !input
        .get(cursor..cursor + 7)?
        .eq_ignore_ascii_case(b"ZMSCORE")
    {
        return None;
    }
    cursor += 7;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (key, mut next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let empty: &[u8] = &[];
    let mut fields = [empty; HMGET_MULTI_MAX];
    let mut consumed = next;
    for slot in fields.iter_mut().take(nmembers) {
        let (m, n2) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
        *slot = m;
        next = n2;
        consumed = n2;
    }
    Some(BorrowedPlainHmgetMultiPacket {
        consumed,
        key,
        fields,
        len: nmembers,
    })
}

