// (frankenredis-setexfast) Byte-prefix fast path for the no-flag `SET key value
// EX|PX time` (5-element, the dominant set-with-TTL). Requires a literal EX or PX
// token in slot 3 (returns is_seconds: EX=true, PX=false); EXAT/PXAT/NX/XX/GET/
// KEEPTTL and every other shape fall through to the generic. Reuses
// BorrowedPlainKeyRangePacket (start = value, end = time).
fn parse_borrowed_plain_set_relexpire_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<(bool, BorrowedPlainKeyRangePacket<'a>)> {
    if config.max_array_len < 5 || config.max_bulk_len < b"SET".len() {
        return None;
    }
    let mut cursor = input.strip_prefix(b"*5\r\n$3\r\n").and_then(|rest| {
        rest.get(..3)
            .filter(|command| command.eq_ignore_ascii_case(b"SET"))
            .map(|_| input.len() - rest.len() + 3)
    })?;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (key, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let (value, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    let (unit, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    let is_seconds = if unit.eq_ignore_ascii_case(b"EX") {
        true
    } else if unit.eq_ignore_ascii_case(b"PX") {
        false
    } else {
        return None;
    };
    let (time, consumed) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    Some((
        is_seconds,
        BorrowedPlainKeyRangePacket {
            consumed,
            key,
            start: value,
            end: time,
        },
    ))
}

// (frankenredis-setexget) `SET key value EX|PX n GET` (*6) — set-with-relative-TTL
// returning the old value. Like set_relexpire but with a trailing literal GET token;
// the runtime reads the old value before writing. GET-first order / EXAT/PXAT / NX/XX
// fall through to the generic. Reuses BorrowedPlainKeyRangePacket (start=value, end=time).
fn parse_borrowed_plain_set_relexpire_get_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<(bool, BorrowedPlainKeyRangePacket<'a>)> {
    if config.max_array_len < 6 || config.max_bulk_len < b"SET".len() {
        return None;
    }
    let mut cursor = input.strip_prefix(b"*6\r\n$3\r\n").and_then(|rest| {
        rest.get(..3)
            .filter(|command| command.eq_ignore_ascii_case(b"SET"))
            .map(|_| input.len() - rest.len() + 3)
    })?;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (key, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let (value, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    let (unit, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    let is_seconds = if unit.eq_ignore_ascii_case(b"EX") {
        true
    } else if unit.eq_ignore_ascii_case(b"PX") {
        false
    } else {
        return None;
    };
    let (time, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    let (get_tok, consumed) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    if !get_tok.eq_ignore_ascii_case(b"GET") {
        return None;
    }
    Some((
        is_seconds,
        BorrowedPlainKeyRangePacket {
            consumed,
            key,
            start: value,
            end: time,
        },
    ))
}

// (frankenredis-setoptget) `SET key value OPT GET` (*5) where OPT ∈ {NX, XX,
// KEEPTTL} — conditional/keep-ttl set that also returns the old value. Slot-3 must
// be a literal NX/XX/KEEPTTL and slot-4 a literal GET; the runtime reads the old
// value, applies the option, and replies the old value. EX/PX/EXAT/PXAT+GET, the
// GET-first order, and 2-option forms fall through to the generic. Reuses
// BorrowedPlainKeyRangePacket (start=value, end=the OPT token).
fn parse_borrowed_plain_set_opt_get_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainKeyRangePacket<'a>> {
    if config.max_array_len < 5 || config.max_bulk_len < b"SET".len() {
        return None;
    }
    let mut cursor = input.strip_prefix(b"*5\r\n$3\r\n").and_then(|rest| {
        rest.get(..3)
            .filter(|command| command.eq_ignore_ascii_case(b"SET"))
            .map(|_| input.len() - rest.len() + 3)
    })?;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (key, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let (value, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    let (opt, next) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    if !(opt.eq_ignore_ascii_case(b"NX")
        || opt.eq_ignore_ascii_case(b"XX")
        || opt.eq_ignore_ascii_case(b"KEEPTTL"))
    {
        return None;
    }
    let (get_tok, consumed) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    if !get_tok.eq_ignore_ascii_case(b"GET") {
        return None;
    }
    Some(BorrowedPlainKeyRangePacket {
        consumed,
        key,
        start: value,
        end: opt,
    })
}

// (frankenredis-setatfast) Byte-prefix fast path for `SET key value EXAT|PXAT ts`
