/// Max key/value pairs served by the MSET borrowed multi fast path. Beyond this
/// an MSET packet falls through to the generic borrowed dispatch.
const MSET_MULTI_MAX: usize = 32;

struct BorrowedPlainMsetMultiPacket<'a> {
    consumed: usize,
    pairs: [(&'a [u8], &'a [u8]); MSET_MULTI_MAX],
    len: usize,
}

// (CrimsonHawk) MSET borrowed multi fast path. The exact-N parsers only cover 2-8
// pairs, so a 9..=32-pair MSET dropped to the much slower generic borrowed
// dispatch — measured 0.55x @9 pairs vs Redis 7.2.4 (8 pairs are at parity). Parses
// the array count generically (with a non-canonical leading-zero guard) into a
// `[(&[u8], &[u8]); 32]` array, reusing the byte-exact
// `execute_plain_mset_borrowed` executor. Serves 9..=32 pairs; <=8 keep their
// exact-N paths; >32 defers.
fn parse_borrowed_plain_mset_multi_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainMsetMultiPacket<'a>> {
    if config.max_bulk_len < b"MSET".len() {
        return None;
    }
    let rest = input.strip_prefix(b"*")?;
    if rest.first() == Some(&b'0') {
        return None;
    }
    let mut i = 0usize;
    let mut arr_len = 0usize;
    while let Some(&b) = rest.get(i) {
        if !b.is_ascii_digit() {
            break;
        }
        arr_len = arr_len.checked_mul(10)?.checked_add((b - b'0') as usize)?;
        i += 1;
        if i > 3 {
            return None;
        }
    }
    if i == 0 || rest.get(i..i + 2)? != b"\r\n" {
        return None;
    }
    // arr_len = 1 (MSET) + 2*npairs, always ODD; serve 9..=MAX pairs (arr_len >= 19).
    if arr_len < 19 || arr_len % 2 == 0 {
        return None;
    }
    let npairs = (arr_len - 1) / 2;
    if npairs > MSET_MULTI_MAX || config.max_array_len < arr_len {
        return None;
    }
    // Command bulk: `$4\r\nMSET\r\n` (case-insensitive name).
    let mut cursor = 1 + i + 2;
    if input.get(cursor..cursor + 4)? != b"$4\r\n" {
        return None;
    }
    cursor += 4;
    if !input.get(cursor..cursor + 4)?.eq_ignore_ascii_case(b"MSET") {
        return None;
    }
    cursor += 4;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let empty: &[u8] = &[];
    let mut pairs = [(empty, empty); MSET_MULTI_MAX];
    let mut next = cursor;
    let mut consumed = cursor;
    for slot in pairs.iter_mut().take(npairs) {
        let (k, n1) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
        let (v, n2) = parse_borrowed_plain_set_bulk(input, n1, config.max_bulk_len)?;
        *slot = (k, v);
        next = n2;
        consumed = n2;
    }
    Some(BorrowedPlainMsetMultiPacket {
        consumed,
        pairs,
        len: npairs,
    })
}

enum BorrowedPlainMsetPacket<'a> {
    Two(BorrowedPlainMsetTwoPacket<'a>),
    Three(BorrowedPlainMsetThreePacket<'a>),
    Four(BorrowedPlainMsetFourPacket<'a>),
    Five(BorrowedPlainMsetFivePacket<'a>),
    Six(BorrowedPlainMsetSixPacket<'a>),
    Seven(BorrowedPlainMsetSevenPacket<'a>),
    Eight(BorrowedPlainMsetEightPacket<'a>),
    Multi(BorrowedPlainMsetMultiPacket<'a>),
}

impl<'a> BorrowedPlainMsetPacket<'a> {
    fn consumed(&self) -> usize {
        match self {
            Self::Two(packet) => packet.consumed,
            Self::Three(packet) => packet.consumed,
            Self::Four(packet) => packet.consumed,
            Self::Five(packet) => packet.consumed,
            Self::Six(packet) => packet.consumed,
            Self::Seven(packet) => packet.consumed,
            Self::Eight(packet) => packet.consumed,
            Self::Multi(packet) => packet.consumed,
        }
    }

    fn pairs(&self) -> &[(&'a [u8], &'a [u8])] {
        match self {
            Self::Two(packet) => &packet.pairs,
            Self::Three(packet) => &packet.pairs,
            Self::Four(packet) => &packet.pairs,
            Self::Five(packet) => &packet.pairs,
            Self::Six(packet) => &packet.pairs,
            Self::Seven(packet) => &packet.pairs,
            Self::Eight(packet) => &packet.pairs,
            Self::Multi(packet) => &packet.pairs[..packet.len],
        }
    }
}

// (frankenredis-ohsk5) Jump directly to the exact MSET parser selected by the
// canonical RESP array header. The previous call site probed 2,3,4,...,8-pair
// parsers linearly, so an 8-pair packet paid six guaranteed failed prefix
// checks before the real parse. Noncanonical and unsupported arities still fall
// through to the generic borrowed parser.
fn parse_borrowed_plain_mset_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainMsetPacket<'a>> {
    if input.starts_with(b"*5\r\n") {
        parse_borrowed_plain_mset_two_packet(input, config).map(BorrowedPlainMsetPacket::Two)
    } else if input.starts_with(b"*7\r\n") {
        parse_borrowed_plain_mset_three_packet(input, config).map(BorrowedPlainMsetPacket::Three)
    } else if input.starts_with(b"*9\r\n") {
        parse_borrowed_plain_mset_four_packet(input, config).map(BorrowedPlainMsetPacket::Four)
    } else if input.starts_with(b"*11\r\n") {
        parse_borrowed_plain_mset_five_packet(input, config).map(BorrowedPlainMsetPacket::Five)
    } else if input.starts_with(b"*13\r\n") {
        parse_borrowed_plain_mset_six_packet(input, config).map(BorrowedPlainMsetPacket::Six)
    } else if input.starts_with(b"*15\r\n") {
        parse_borrowed_plain_mset_seven_packet(input, config).map(BorrowedPlainMsetPacket::Seven)
    } else if input.starts_with(b"*17\r\n") {
        parse_borrowed_plain_mset_eight_packet(input, config).map(BorrowedPlainMsetPacket::Eight)
    } else {
        parse_borrowed_plain_mset_multi_packet(input, config).map(BorrowedPlainMsetPacket::Multi)
    }
}

struct BorrowedPlainMgetTwoPacket<'a> {
    consumed: usize,
    keys: [&'a [u8]; 2],
}

fn parse_borrowed_plain_mget_two_packet<'a>(
    input: &'a [u8],
    config: &ParserConfig,
) -> Option<BorrowedPlainMgetTwoPacket<'a>> {
    if config.max_array_len < 3 || config.max_bulk_len < b"MGET".len() {
        return None;
    }
    let mut cursor = input.strip_prefix(b"*3\r\n$4\r\n").and_then(|rest| {
        rest.get(..4)
            .filter(|command| command.eq_ignore_ascii_case(b"MGET"))
            .map(|_| input.len() - rest.len() + 4)
    })?;
    if input.get(cursor..cursor + 2)? != b"\r\n" {
        return None;
    }
    cursor += 2;
    let (first_key, next) = parse_borrowed_plain_set_bulk(input, cursor, config.max_bulk_len)?;
    let (second_key, consumed) = parse_borrowed_plain_set_bulk(input, next, config.max_bulk_len)?;
    Some(BorrowedPlainMgetTwoPacket {
        consumed,
        keys: [first_key, second_key],
    })
}

